Add JavaScript functionality for tool badge popovers - show tool details on hover/focus.

## Current State
scripts.rs has theme toggle, search, and encryption JS but no popover handling.

## Required Functionality

### 1. Popover Show/Hide
```javascript
// Tool badge popover controller
(function() {
  const badges = document.querySelectorAll('.tool-badge');

  badges.forEach(badge => {
    const popover = badge.querySelector('.tool-popover');
    if (!popover) return;

    // Show on hover/focus
    badge.addEventListener('mouseenter', () => showPopover(badge, popover));
    badge.addEventListener('focus', () => showPopover(badge, popover));

    // Hide on leave/blur
    badge.addEventListener('mouseleave', () => hidePopover(badge, popover));
    badge.addEventListener('blur', () => hidePopover(badge, popover));

    // Toggle on click/Enter for mobile
    badge.addEventListener('click', (e) => {
      e.preventDefault();
      togglePopover(badge, popover);
    });
    badge.addEventListener('keydown', (e) => {
      if (e.key === 'Enter' || e.key === ' ') {
        e.preventDefault();
        togglePopover(badge, popover);
      }
      if (e.key === 'Escape') {
        hidePopover(badge, popover);
      }
    });
  });

  function showPopover(badge, popover) {
    popover.classList.add('visible');
    badge.setAttribute('aria-expanded', 'true');
    positionPopover(badge, popover);
  }

  function hidePopover(badge, popover) {
    popover.classList.remove('visible');
    badge.setAttribute('aria-expanded', 'false');
  }

  function togglePopover(badge, popover) {
    const isVisible = popover.classList.contains('visible');
    if (isVisible) {
      hidePopover(badge, popover);
    } else {
      showPopover(badge, popover);
    }
  }

  function positionPopover(badge, popover) {
    // Position below badge, handle viewport overflow
    const rect = badge.getBoundingClientRect();
    const popRect = popover.getBoundingClientRect();

    // Default: below and right-aligned
    let top = rect.bottom + 8;
    let left = rect.left;

    // Flip up if near bottom
    if (top + popRect.height > window.innerHeight - 20) {
      top = rect.top - popRect.height - 8;
    }

    // Flip left if near right edge
    if (left + popRect.width > window.innerWidth - 20) {
      left = rect.right - popRect.width;
    }

    popover.style.top = top + 'px';
    popover.style.left = left + 'px';
  }
})();
```

